import React, { useState, useEffect } from "react";
import MapComponent from "./MapComponent";
import BusCharts from "./BusCharts";

function App() {
  const [buses, setBuses] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [showChart, setShowChart] = useState(false);

  // Fetch live bus data every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data);
      } catch (err) {
        console.error("Error fetching buses:", err);
      }
    };

    const fetchAlerts = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/alerts");
        const data = await res.json();
        setAlerts(data);
      } catch (err) {
        console.error("Error fetching alerts:", err);
      }
    };

    fetchBuses();
    fetchAlerts();
    const interval = setInterval(() => {
      fetchBuses();
      fetchAlerts();
    }, 120000); // 2 minutes
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      <h1>Ghost Bus Detector</h1>

      {/* Alerts */}
      <div style={{ color: "red", fontWeight: "bold", margin: "10px 0" }}>
        {alerts.length > 0 ? alerts.map((alert, idx) => <div key={idx}>{alert}</div>) : "No alerts"}
      </div>

      {/* Toggle Chart Button */}
      <button onClick={() => setShowChart(!showChart)} style={{ marginBottom: "10px" }}>
        {showChart ? "Hide Trend Chart" : "Show Trend Chart"}
      </button>

      {/* Chart */}
      {showChart && <BusCharts buses={buses} />}

      {/* Map */}
      <MapComponent buses={buses} />
    </div>
  );
}

export default App;
